{
  "expo": {
    "name": "Prabha Skincare",
    "slug": "prabha-skincare",
    "description": "Prabha is a personalized skincare companion designed for Nepal's weather, water, food, budget, festivals, makeup habits, and local products.",
    "keywords": ["skincare", "beauty", "nepal", "routine", "skin", "glow", "prabha"],
    "version": "1.0.0",
    "orientation": "portrait",
    "scheme": "prabha",
    "icon": "./assets/brand/prabha-icon-1024.png",
    "userInterfaceStyle": "automatic",
    "newArchEnabled": true,
    "splash": {
      "image": "./assets/brand/prabha-logo-cream.png",
      "resizeMode": "contain",
      "backgroundColor": "#FDF8F5"
    },
    "ios": {
      "icon": "./assets/brand/prabha-icon-1024.png",
      "bundleIdentifier": "com.prabha.skincare",
      "buildNumber": "1",
      "infoPlist": {
        "NSCameraUsageDescription": "Prabha uses camera access only when you choose to add progress photos.",
        "NSPhotoLibraryUsageDescription": "Prabha uses photo access only when you choose to upload progress photos.",
        "NSLocationWhenInUseUsageDescription": "Prabha uses your location to show local weather and air quality skincare guidance."
      }
    },
    "android": {
      "package": "com.prabha.skincare",
      "versionCode": 1,
      "permissions": ["CAMERA", "READ_MEDIA_IMAGES", "ACCESS_FINE_LOCATION"],
      "adaptiveIcon": {
        "foregroundImage": "./assets/brand/prabha-adaptive-icon.png",
        "backgroundColor": "#F98B9E"
      }
    },
    "web": {
      "bundler": "metro",
      "output": "single",
      "favicon": "./assets/brand/prabha-favicon.png"
    },
    "plugins": [
      "expo-router",
      "expo-notifications",
      "expo-localization",
      [
        "expo-location",
        {
          "locationWhenInUsePermission": "Prabha uses your location to show local weather and air quality skincare guidance."
        }
      ]
    ],
    "extra": {
      "privacyPolicyUrl": "https://prabhaskincare.com/privacy",
      "termsOfServiceUrl": "https://prabhaskincare.com/terms"
    },
    "experiments": {
      "typedRoutes": true
    }
  }
}

import { Stack } from "expo-router";
import { StatusBar } from "expo-status-bar";
import { AppProvider, useApp } from "@/shared/AppContext";
import { AppAtmosphere } from "@/shared/components";
import { palettes } from "@/shared/theme";

function RootStack() {
  const { themeMode } = useApp();
  const c = palettes[themeMode];
  return (
    <>
      <StatusBar style={themeMode === "dark" ? "light" : "dark"} />
      <AppAtmosphere>
        <Stack
          screenOptions={{
            headerStyle: { backgroundColor: c.bg },
            headerTintColor: c.text,
            headerShadowVisible: false,
            contentStyle: { backgroundColor: c.bg }
          }}
        >
          <Stack.Screen name="index" options={{ headerShown: false }} />
          <Stack.Screen name="onboarding" options={{ title: "Onboarding" }} />
          <Stack.Screen name="(tabs)" options={{ headerShown: false }} />
          <Stack.Screen name="learn/[id]" options={{ title: "Learn" }} />
          <Stack.Screen name="paywall" options={{ title: "Premium" }} />
          <Stack.Screen name="legal" options={{ title: "Privacy + safety" }} />
        </Stack>
      </AppAtmosphere>
    </>
  );
}

export default function Layout() {
  return (
    <AppProvider>
      <RootStack />
    </AppProvider>
  );
}

import { Tabs } from "expo-router";
import { Feather } from "@expo/vector-icons";
import { useApp } from "@/shared/AppContext";
import { t } from "@/shared/i18n";
import { palettes } from "@/shared/theme";

export default function TabsLayout() {
  const { language, themeMode } = useApp();
  const c = palettes[themeMode];
  return (
    <Tabs
      screenOptions={{
        tabBarActiveTintColor: c.primary,
        tabBarInactiveTintColor: c.muted,
        sceneStyle: { backgroundColor: c.bg },
        tabBarStyle: {
          backgroundColor: c.surface,
          borderTopColor: c.border,
          borderTopWidth: 1,
          height: 64,
          paddingTop: 7,
          paddingBottom: 7
        },
        tabBarLabelStyle: { fontWeight: "800", fontSize: 11 },
        headerStyle: { backgroundColor: c.bg },
        headerTintColor: c.text,
        headerShadowVisible: false
      }}
    >
      <Tabs.Screen name="home" options={{ title: t(language, "dashboard"), tabBarIcon: ({ color, size }) => <Feather name="home" color={color} size={size} /> }} />
      <Tabs.Screen name="progress" options={{ title: t(language, "progress"), tabBarIcon: ({ color, size }) => <Feather name="bar-chart-2" color={color} size={size} /> }} />
      <Tabs.Screen name="products" options={{ title: t(language, "products"), tabBarIcon: ({ color, size }) => <Feather name="package" color={color} size={size} /> }} />
      <Tabs.Screen name="tips" options={{ title: t(language, "tips"), tabBarIcon: ({ color, size }) => <Feather name="zap" color={color} size={size} /> }} />
      <Tabs.Screen name="learn" options={{ title: "Learn", tabBarIcon: ({ color, size }) => <Feather name="book-open" color={color} size={size} /> }} />
      <Tabs.Screen name="community" options={{ title: t(language, "community"), tabBarIcon: ({ color, size }) => <Feather name="help-circle" color={color} size={size} /> }} />
      <Tabs.Screen name="settings" options={{ title: t(language, "settings"), tabBarIcon: ({ color, size }) => <Feather name="settings" color={color} size={size} /> }} />
    </Tabs>
  );
}

import { ScrollView, StyleSheet, View } from "react-native";
import { router } from "expo-router";
import { useApp } from "@/shared/AppContext";
import { Body, BrandMark, Button, Card, H1, H2, Pill, Screen, SectionLabel } from "@/shared/components";
import { questions } from "@/shared/data";
import { t } from "@/shared/i18n";
import { learnQAs } from "@/shared/knowledge/education";
import { palettes, spacing } from "@/shared/theme";

export default function Community() {
  const { language, themeMode, tier, setTier } = useApp();
  const c = palettes[themeMode];
  const locked = tier !== "premium";
  return (
    <Screen>
      <ScrollView contentContainerStyle={styles.content}>
        <Card variant="hero">
          <View style={styles.heroRow}>
            <BrandMark compact />
            <View style={styles.flex}>
              <SectionLabel tone="accent">{language === "en" ? "Q&A" : "Q&A"}</SectionLabel>
              <H1>{t(language, "community")}</H1>
              <Body muted>{language === "en" ? "Nepal-context doubts in simple spoken style, plus premium expert signals later." : "Simple spoken-style answers, premium expert signals pachi."}</Body>
            </View>
          </View>
        </Card>

        <Card>
          <View style={styles.titleRow}>
            <H2>{language === "en" ? "Q&A: Nepal context" : "Q&A: Nepal context"}</H2>
            <Pill tone="secondary">{language === "en" ? "Simple English" : "Spoken Nepali"}</Pill>
          </View>
          <Body muted>{language === "en" ? "Clear answers without heavy medical words. Switch to NE for spoken Nepali style." : "Common skincare doubt ko free simple answers. EN ma simple English version cha."}</Body>
          {learnQAs.map((qa, index) => {
            const gated = locked && index >= 12;
            return (
            <View key={qa.id} style={[styles.qaBlock, { backgroundColor: c.surfaceAlt, borderColor: c.border }]}>
              <H2>{gated ? "Premium Q&A archive" : language === "ne" ? qa.question_ne : qa.question_en}</H2>
              <Body>{gated ? "Unlock 50+ Nepal-context Q&As covering periods, makeup, hostel life, sunscreen, water, food, festivals, and product shopping." : language === "ne" ? qa.answer_ne : qa.answer_en}</Body>
              <View style={styles.voteRow}>
                {(gated ? ["premium"] : qa.tags).map((tag) => (
                  <Pill key={tag} tone="primary">{tag}</Pill>
                ))}
                {gated ? <Button label="Unlock Q&A" onPress={() => router.push("/paywall" as never)} secondary /> : null}
              </View>
            </View>
          );})}
        </Card>

        {locked ? (
          <Card>
            <Pill>{t(language, "premium")}</Pill>
            <H2>{language === "en" ? "Ask-an-expert is premium" : "Ask-an-expert premium ho"}</H2>
            <Body muted>{language === "en" ? "Premium can later include anonymous questions, expert validation badges, and clinic referral entry points." : "Premium ma anonymous questions, expert badges ra clinic referral entry points aauna sakcha."}</Body>
            <Button label={t(language, "upgrade")} onPress={() => setTier("premium")} />
          </Card>
        ) : questions.map((question) => (
          <Card key={question.id}>
            {question.verified ? <Pill tone="secondary">{t(language, "verified")}</Pill> : null}
            <H2>{question.title[language]}</H2>
            <Body>{question.answer[language]}</Body>
            <View style={styles.voteRow}>
              <Pill tone="primary">Helpful 24</Pill>
              <Pill tone="accent">Clinic-safe</Pill>
            </View>
          </Card>
        ))}

        <Card>
          <H2>{language === "en" ? "Clinic escalation" : "Clinic escalation"}</H2>
          <Body>{t(language, "disclaimer")}</Body>
        </Card>
      </ScrollView>
    </Screen>
  );
}

const styles = StyleSheet.create({
  content: { gap: spacing.md, paddingBottom: spacing.xl },
  heroRow: { flexDirection: "row", alignItems: "center", gap: spacing.md },
  flex: { flex: 1, gap: spacing.xs },
  titleRow: { flexDirection: "row", justifyContent: "space-between", alignItems: "center", gap: spacing.sm, flexWrap: "wrap" },
  voteRow: { flexDirection: "row", flexWrap: "wrap", gap: spacing.xs },
  qaBlock: { gap: spacing.xs, padding: spacing.md, borderWidth: 1, borderRadius: 8, marginTop: spacing.sm }
});

import { Feather } from "@expo/vector-icons";
import { router } from "expo-router";
import type { ComponentProps, ReactNode } from "react";
import { useEffect, useMemo, useRef, useState } from "react";
import { ActivityIndicator, Pressable, ScrollView, StyleSheet, Text, View } from "react-native";
import { useApp } from "@/shared/AppContext";
import { Body, BrandMark, Button, Card, FloatingBadge, H1, H2, Pill, ProgressBar, Screen, SectionLabel, SignalCard, ToggleGroup } from "@/shared/components";
import { t } from "@/shared/i18n";
import { contextualConditionDescription, generateRoutine, localized } from "@/shared/knowledge/engine";
import { dailyHabitTips } from "@/shared/knowledge/education";
import { buildLifestyleSignals } from "@/shared/knowledge/lifestyleSignals";
import { buildPlanSections, buildTrustReasons, doctorWarning, getMatchConfidence } from "@/shared/knowledge/resultTrust";
import { calculateSkinHabitScore } from "@/shared/knowledge/tracking";
import { GeneratedStep, HomeRemedy } from "@/shared/knowledge/types";
import { buildWeatherActions, WeatherAction } from "@/shared/knowledge/weatherGuidance";
import { premiumPreviewLabel } from "@/shared/monetization";
import { launchProducts } from "@/shared/productCatalog";
import { getAqiGuidance, useEnvironmentalData } from "@/shared/services/environment";
import { trackEvent } from "@/shared/services/analytics";
import { palettes, spacing } from "@/shared/theme";

export default function Home() {
  const { language, setLanguage, themeMode, setThemeMode, tier, setTier, profile, completion, toggleCompletion, todayCheckIn } = useApp();
  const c = palettes[themeMode];
  const scrollRef = useRef<ScrollView>(null);
  const [showTopButton, setShowTopButton] = useState(false);
  const [routinePeriod, setRoutinePeriod] = useState<"morning" | "evening">("morning");
  const [expandedConcernId, setExpandedConcernId] = useState<string | null>(null);
  const environment = useEnvironmentalData();
  const result = useMemo(() => generateRoutine(profile.quiz), [profile.quiz]);
  const lifestyleSignals = useMemo(() => buildLifestyleSignals(profile, todayCheckIn), [profile, todayCheckIn]);
  const weatherActions = useMemo(() => (environment.data ? buildWeatherActions(environment.data) : []), [environment.data]);
  const visibleEvening = useMemo(() => (tier === "premium" ? result.evening : result.evening.slice(0, 4)), [result.evening, tier]);
  const routineSteps = useMemo(() => [...result.morning, ...visibleEvening], [result.morning, visibleEvening]);
  const completed = routineSteps.filter((step) => completion[step.id]).length;
  const percent = routineSteps.length ? Math.round((completed / routineSteps.length) * 100) : 0;
  const habitScore = useMemo(
    () => calculateSkinHabitScore({ completion, routineSteps, profile, checkIn: todayCheckIn, weatherActions }),
    [completion, profile, routineSteps, todayCheckIn, weatherActions]
  );
  const topMatch = result.matches[0];
  const activeSteps = routinePeriod === "morning" ? result.morning : visibleEvening;
  const remedies = useMemo(() => collectRemedies(topMatch ? [topMatch.condition] : []), [topMatch]);
  const topAction = result.morning[0]?.action ?? result.evening[0]?.action ?? "Start with a gentle cleanser";
  const productMatches = launchProducts
    .filter((item) => item.fit.includes(profile.skinType) && (tier === "premium" || item.budgetTier === profile.budgetTier))
    .slice(0, 3);
  const trustReasons = topMatch ? buildTrustReasons(topMatch, profile.quiz) : [];
  const planSections = useMemo(() => buildPlanSections(result, productMatches), [result, productMatches]);

  useEffect(() => {
    if (topMatch) {
      trackEvent("result_viewed", { condition: topMatch.condition.id, score: topMatch.score, tier });
    }
  }, [topMatch, tier]);

  return (
    <Screen showQuickActions={false}>
      <View style={styles.quickActions}>
        <View style={styles.quickButtonRow}>
          <QuickIconButton
            icon={themeMode === "dark" ? "sun" : "moon"}
            onPress={() => setThemeMode(themeMode === "dark" ? "light" : "dark")}
            background={c.surface}
            color={c.primary}
            border={c.borderStrong}
          />
          <QuickTextButton
            label={language === "en" ? "EN" : "ने"}
            onPress={() => setLanguage(language === "en" ? "ne" : "en")}
            background={c.surface}
            color={c.text}
            border={c.borderStrong}
          />
        </View>
        <ScoreBubble score={habitScore.score} percent={percent} completed={completed} total={routineSteps.length} colors={c} />
      </View>

      <ScrollView
        ref={scrollRef}
        onScroll={({ nativeEvent }) => setShowTopButton(nativeEvent.contentOffset.y > 260)}
        scrollEventThrottle={16}
        contentContainerStyle={styles.content}
      >
        <View style={styles.header}>
          <View style={styles.headerCopy}>
            <Pill tone={tier === "premium" ? "accent" : "primary"}>{tier === "premium" ? t(language, "premium") : t(language, "free")}</Pill>
            <H1>{language === "en" ? `Namaste, ${profile.name}` : `नमस्ते, ${profile.name}`}</H1>
            <View style={styles.badgeRow}>
              <FloatingBadge label="Nepal weather-aware" />
              <FloatingBadge label={`${profile.quiz.environment.location_type ?? profile.location} region`} tone="secondary" />
              <FloatingBadge label={`${profile.budgetTier} budget`} tone="accent" />
            </View>
          </View>
        </View>

        <Card variant="hero">
          <View style={styles.heroRow}>
            <BrandMark />
            <View style={styles.flex}>
              <SectionLabel tone="accent">{language === "en" ? "Today's skin read" : "Today's skin read"}</SectionLabel>
              <H2>{topMatch ? localized(language, topMatch.condition.name_en, topMatch.condition.name_ne) : "Skin guidance is ready"}</H2>
              <Body muted>{language === "en" ? `Top action: ${topAction}. Guidance only, not diagnosis.` : `Top action: ${topAction}. Guidance only, diagnosis होइन।`}</Body>
            </View>
          </View>
          <ProgressBar value={Math.min((topMatch?.score ?? 0) * 10, 100)} color={c.primary} />
        </Card>

        <EnvironmentalCard environment={environment} colors={c} />

        {weatherActions.length > 0 ? (
          <Card>
            <View style={styles.sectionTitle}>
              <Feather name="cloud" color={c.secondary} size={22} />
              <H2>Today's weather actions</H2>
            </View>
            {weatherActions.slice(0, 4).map((action) => (
              <WeatherActionCard key={action.id} action={action} />
            ))}
          </Card>
        ) : null}

        <Card>
          <H2>{language === "en" ? "Matched skin concern" : "Matched skin concern"}</H2>
          {topMatch ? (
            <>
              <View style={styles.row}>
                <Pill tone="secondary">Score {topMatch.score}</Pill>
                <Pill tone={topMatch.score >= 8 ? "secondary" : topMatch.score >= 5 ? "accent" : "primary"}>{getMatchConfidence(topMatch.score)}</Pill>
                <Pill>{topMatch.condition.severity}</Pill>
              </View>
              <H2>{localized(language, topMatch.condition.name_en, topMatch.condition.name_ne)}</H2>
              <Body muted>{contextualConditionDescription(topMatch.condition, profile.quiz, language)}</Body>
              <Body>{language === "en" ? "Recommended guidance only, not a medical diagnosis." : "यो recommended guidance मात्र हो, medical diagnosis होइन।"}</Body>
            </>
          ) : (
            <Body muted>{language === "en" ? "No strong condition match yet. Add more symptoms in onboarding." : "अहिले strong match छैन। onboarding मा थप symptoms छान्नुहोस्।"}</Body>
          )}
        </Card>

        {topMatch ? (
          <Card variant="seasonal">
            <View style={styles.sectionTitle}>
              <Feather name="shield" color={c.secondary} size={22} />
              <H2>Why we think this</H2>
            </View>
            <Body muted>Transparent reasons from your symptoms, location, lifestyle, water, age, and current routine.</Body>
            {trustReasons.map((reason) => (
              <View key={reason} style={styles.reasonLine}>
                <Feather name="check-circle" color={c.secondary} size={16} />
                <Body>{reason}</Body>
              </View>
            ))}
          </Card>
        ) : null}

        {topMatch ? (
          <Card>
            <View style={styles.sectionTitleBetween}>
              <View style={styles.sectionTitle}>
                <Feather name="map" color={c.primary} size={22} />
                <H2>Your Plan</H2>
              </View>
              <Pill tone={tier === "premium" ? "secondary" : "accent"}>{premiumPreviewLabel(tier)}</Pill>
            </View>
            {planSections.map((section, index) => {
              const locked = tier !== "premium" && index >= 2;
              return (
                <View key={section.title} style={[styles.planTile, { borderColor: c.border, backgroundColor: c.surfaceAlt }]}>
                  <Pill tone={locked ? "accent" : "primary"}>{locked ? "Premium depth" : `Step ${index + 1}`}</Pill>
                  <H2>{section.title}</H2>
                  <Body muted>{locked ? "Unlock full personalized detail, local product alternatives, and weekly adjustment logic." : section.body}</Body>
                  {locked ? <Button label="See premium value" onPress={() => router.push("/paywall" as never)} secondary /> : null}
                </View>
              );
            })}
          </Card>
        ) : null}

        {result.matches.length > 0 ? (
          <Card>
            <H2>{language === "en" ? "Other likely concerns" : "Other likely concerns"}</H2>
            <View style={styles.row}>
              {result.matches.map((match) => (
                <Pill key={match.condition.id} tone={match === topMatch ? "accent" : "secondary"}>
                  {localized(language, match.condition.name_en, match.condition.name_ne)} • {match.score}
                </Pill>
              ))}
            </View>
          </Card>
        ) : null}

        {result.matches.length > 0 ? (
          <Card variant="accent">
            <H2>{language === "en" ? "Concern details" : "Concern details"}</H2>
            {result.matches.map((match) => {
              const expanded = expandedConcernId === match.condition.id;
              return (
                <Pressable
                  key={match.condition.id}
                  onPress={() => setExpandedConcernId(expanded ? null : match.condition.id)}
                  style={({ pressed }) => [
                    styles.concernCard,
                    {
                      borderColor: expanded ? c.borderStrong : c.border,
                      backgroundColor: expanded ? c.surfaceAlt : c.surface,
                      transform: [{ scale: pressed ? 0.99 : 1 }]
                    }
                  ]}
                >
                  <View style={styles.row}>
                    <Pill tone={match === topMatch ? "accent" : "secondary"}>Score {match.score}</Pill>
                    <Feather name={expanded ? "chevron-up" : "chevron-down"} color={c.muted} size={18} />
                  </View>
                  <Body>{localized(language, match.condition.name_en, match.condition.name_ne)}</Body>
                  {expanded ? (
                    <>
                      <Pill tone={match.score >= 8 ? "secondary" : match.score >= 5 ? "accent" : "primary"}>{getMatchConfidence(match.score)}</Pill>
                      <Body muted>{contextualConditionDescription(match.condition, profile.quiz, language)}</Body>
                      <Body muted>Why: {buildTrustReasons(match, profile.quiz).slice(0, 3).join(" ")}</Body>
                    </>
                  ) : null}
                </Pressable>
              );
            })}
          </Card>
        ) : null}

        {topMatch ? (
          <Card>
            <View style={styles.sectionTitle}>
              <Feather name="alert-triangle" color={c.danger} size={22} />
              <H2>Doctor warning signs</H2>
            </View>
            <Body>{doctorWarning(topMatch)}</Body>
            <Body muted>Guidance only, not diagnosis. Painful, spreading, infected, or scarring concerns deserve medical care.</Body>
          </Card>
        ) : null}

        {result.contextTips.length > 0 ? (
          <Card>
            <H2>{language === "en" ? "Lifestyle notes for your plan" : "Lifestyle notes"}</H2>
            {result.contextTips.map((tip) => (
              <View key={`${tip.category}-${tip.text.en}`} style={styles.tipLine}>
                <Pill tone={tip.category === "smoking" || tip.category === "alcohol" ? "accent" : "secondary"}>{tip.category}</Pill>
                <Body>{tip.text[language]}</Body>
              </View>
            ))}
          </Card>
        ) : null}

        {lifestyleSignals.length > 0 ? (
          <Card>
            <H2>Your Lifestyle Signals</H2>
            <Body muted>Every quiz and check-in answer should visibly change your plan. These are the strongest signals today.</Body>
            {lifestyleSignals.slice(0, 6).map((signal) => (
              <SignalCard key={signal.id} tone={signal.tone} icon={signal.icon} label={signal.label} title={signal.title}>
                {signal.body}
              </SignalCard>
            ))}
          </Card>
        ) : null}

        <Card>
          <View style={styles.sectionTitleBetween}>
            <View style={styles.sectionTitle}>
              <Feather name="check-circle" color={c.secondary} size={22} />
              <H2>Daily healthy habits</H2>
            </View>
            <Button label="View all" onPress={() => router.push("/(tabs)/learn" as never)} secondary />
          </View>
          <Body muted>Small Nepal-friendly habits that support the routine you are completing today.</Body>
          {dailyHabitTips.slice(0, 3).map((tip) => (
            <HabitPreviewCard key={tip.id} tip={tip} colors={c} />
          ))}
        </Card>

        <Card>
          <H2>{language === "en" ? "Routine streak" : "Routine streak"}</H2>
          <Body>{language === "en" ? `You followed ${percent}% of today's generated routine. Missed a step? No stress, restart with cleanser.` : `आजको generated routine ${percent}% पूरा भयो। छुट्यो भने cleanser बाट restart गर्नुहोस्।`}</Body>
          <ProgressBar value={percent} color={c.secondary} />
        </Card>

        <Card>
          <View style={styles.scoreHeader}>
            <View style={styles.sectionTitle}>
              <Feather name={routinePeriod === "morning" ? "sun" : "droplet"} color={routinePeriod === "morning" ? c.accent : c.secondary} size={22} />
              <H2>{language === "en" ? "Routine ritual" : "Routine ritual"}</H2>
            </View>
            <Pill tone="secondary">{`Today ${percent}% • ${completed}/${routineSteps.length} done`}</Pill>
          </View>
          <ProgressBar value={percent} color={c.primary} />
          <ToggleGroup
            value={routinePeriod}
            options={[
              { label: t(language, "morning"), value: "morning" },
              { label: t(language, "evening"), value: "evening" }
            ]}
            onChange={setRoutinePeriod}
          />
          <RoutineSection title={routinePeriod === "morning" ? t(language, "morning") : t(language, "evening")} icon={null} steps={activeSteps} />
        </Card>

        {result.weekly.length > 0 ? (
          <Card>
            <View style={styles.sectionTitle}>
              <Feather name="calendar" color={c.primary} size={22} />
              <H2>{language === "en" ? "Weekly add-ons" : "Weekly add-ons"}</H2>
            </View>
            {result.weekly.map((step) => (
              <View key={step.id} style={styles.tipLine}>
                <Pill tone="accent">{step.frequency}</Pill>
                <Body>{step.action}</Body>
                <Body muted>{step.instruction[language]}</Body>
              </View>
            ))}
          </Card>
        ) : null}

        <Card>
