              <Button
                label={locked ? "Unlock smart match" : "Daraz / Pharmacy"}
                onPress={() => {
                  trackEvent("product_clicked", { id: item.id, locked, sponsored: item.sponsored ?? false });
                  return locked ? router.push("/paywall" as never) : Linking.openURL(item.affiliateUrl);
                }}
                secondary
              />
            </View>
          </Card>
        );})}
      </ScrollView>
