            label="Developer sync test"
            onPress={async () => {
              const result = await syncUserSnapshot({ profile, subscription, dailyCheckIns });
              setSyncStatus(result.ok ? `Ready: ${result.mode}` : `Not connected yet: ${result.mode}`);
