            ) : null}

            {articleNutrients.length > 0 ? (
              <Card>
                <H2>Nutrients connected to this guide</H2>
                {articleNutrients.map((nutrient) => (
                  <View key={nutrient.id} style={[styles.tile, { backgroundColor: c.surfaceAlt, borderColor: c.border }]}>
