  "blackheads",
  "whiteheads",
  "dry_patches",
  "flaking",
  "tightness_after_wash",
  "shiny_tzone",
  "redness_after_products",
  "burning_sensation",
  "dark_spots_post_acne",
  "dark_spots_sun",
  "melasma_patches",
  "dull_grey_skin",
  "uneven_skin_tone",
  "under_eye_dark",
  "under_eye_puffy",
  "rough_bumpy_texture",
  "large_visible_pores",
  "itchy_patches",
  "itchy_uniform_bumps",
  "sweat_rash_heat_bumps",
  "wrinkles"
];

